(function(){"use strict";const e=$.fn.dataTable.render.text();$("#cartable").DataTable({fixedHeader:!0,responsive:!0,pageLength:25,scrollX:!0,lengthMenu:[[25,50,100,-1],[25,50,100,"All"]],order:[[0,"asc"]],language:{emptyTable:"No Data"},processing:!0,serverSide:!0,serverMethod:"post",ajax:{url:"../../api/cars/factory-list.php",dataSrc:"data",data:function(r){r.csrf=window.factoryListConfig.csrf},error:function(r,t,n){console.error("Factory table load failed:",t,r.status,n);const a=$("#cartable").closest(".dataTables_wrapper");a.find(".alert-danger").length||a.prepend('<div class="alert alert-danger mt-2">Could not load factory data. Please refresh the page.</div>')}},columns:[{data:"id",searchable:!1,orderable:!1,visible:!1,render:e},{data:"year",render:e},{data:"month",render:e},{data:"batch",render:e},{data:"type",render:e},{data:"serial",render:e},{data:"suffix",render:e},{data:"engineletter",render:e},{data:"enginenumber",render:e},{data:"gearbox",render:e},{data:"color",render:e},{data:"builddate",render:e},{data:"note",render:e},{data:"car_id",render:function(r,t,n){if(t!=="display")return r||"";const a=parseInt(r,10);return'<div class="registry-link-container">'+(Number.isFinite(a)&&a>0?'<a href="'+window.factoryListConfig.urlRoot+"app/owner/cars/details.php?car_id="+a+'" class="btn btn-sm btn-primary" target="_blank"><i class="fas fa-car"></i> View Car #'+a+"</a>":'<span class="text-muted small"><i class="fas fa-times-circle"></i> Not in registry</span>')+"</div>"},orderable:!1,searchable:!1}]})})();
